/**
 * Generates SEO blog article category files (50 articles).
 * Run: node scripts/gen-seo-articles.mjs
 */
import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const OUT = path.join(__dirname, "../src/lib/blog/seo-articles");

