function sectionsToHtml(sections) {
  return sections.map((section) => {
    const parts = [];
    if (section.h2) parts.push(`<h2>${section.h2}</h2>`);
    if (section.h3) parts.push(`<h3>${section.h3}</h3>`);
    for (const p of section.paragraphs) parts.push(`<p>${p}</p>`);
    if (section.list?.length) parts.push(`<ul>${section.list.map((i) => `<li>${i}</li>`).join("")}</ul>`);
    return parts.join("\n");
  }).join("\n\n");
}
function faqToHtml(items) {
  return `<h2>Întrebări frecvente</h2>\n` + items.map((i) => `<h3>${i.question}</h3>\n<p>${i.answer}</p>`).join("\n\n");
}
for (const a of allArticles) {
  const html = sectionsToHtml(a.sections) + "\n\n" + faqToHtml(a.faq);
  const wc = countWords(html);
  if (wc < 1500) console.warn(`WARN: ${a.slug} only ${wc} words`);
}
